const fs = require('fs');
const path = require('path');

const repoRoot = process.cwd();

function normalizePath(filePath) {
  return filePath.split(path.sep).join('/');
}

function readExecutionLog(logPath) {
  const resolved = path.resolve(logPath);
  return JSON.parse(fs.readFileSync(resolved, 'utf8'));
}

function unique(items) {
  return [...new Set(items.filter(Boolean))];
}

function extractFilePaths(text) {
  const matches = [];
  const patterns = [
    /((?:apps|\.github|postman)\/[A-Za-z0-9._/\-]+?\.[A-Za-z0-9]+)/g,
    /(README\.md|\.orchestrator\.yml)/g,
    /(src\/[A-Za-z0-9._/\-]+?\.[A-Za-z0-9]+)/g,
  ];

  for (const pattern of patterns) {
    for (const match of String(text || '').matchAll(pattern)) {
      matches.push(match[1]);
    }
  }

  return unique(matches.map(normalizePath));
}

function inferCategory(text) {
  const haystack = String(text || '').toLowerCase();

  if (/npm audit|vulnerab|ghsa-|severity:/i.test(haystack)) {
    return 'dependency_scan';
  }

  if (/ts\d{4}|typescript|tsc|vite build|syntaxerror|cannot find name|declaration or statement expected/i.test(haystack)) {
    return 'typescript_build_failure';
  }

  if (/assert|test(s)? passed|npm test|jest|mocha|expected .* to/i.test(haystack)) {
    return 'test_failure';
  }

  if (/module not found|cannot find module|failed to resolve import/i.test(haystack)) {
    return 'module_resolution_failure';
  }

  if (/yaml|workflow|github actions|unknown check|invalid workflow/i.test(haystack)) {
    return 'config_failure';
  }

  return 'generic_command_failure';
}

function extractPrimaryMessage(text) {
  const lines = String(text || '')
    .split('\n')
    .map((line) => line.trim())
    .filter(Boolean);

  const preferredPatterns = [
    /error/i,
    /failed/i,
    /exception/i,
    /cannot/i,
    /expected/i,
    /severity:/i,
  ];

  for (const pattern of preferredPatterns) {
    const line = lines.find((candidate) => pattern.test(candidate));
    if (line) {
      return line;
    }
  }

  return lines[0] || 'Command failed without a parseable message';
}

function inferPackage(log, filePaths) {
  const cwd = String(log.cwd || '');
  const joined = `${cwd}\n${filePaths.join('\n')}\n${log.command || ''}`;

  if (/apps\/web|web/.test(joined)) {
    return 'apps/web';
  }

  if (/apps\/api|api/.test(joined)) {
    return 'apps/api';
  }

  if (/\.github|workflow/.test(joined)) {
    return '.github';
  }

  return 'repo';
}

function main() {
  const logPath = process.argv[2];

  if (!logPath) {
    throw new Error('Usage: node extract-failure-signature.js <log-json-path>');
  }

  const log = readExecutionLog(logPath);
  const combined = [log.stdout, log.stderr, log.combined_output].filter(Boolean).join('\n');
  const filePaths = extractFilePaths(combined);
  const failure = {
    execution_id: log.execution_id,
    provider: log.provider,
    check_name: log.check_name,
    command: log.command,
    cwd: log.cwd,
    exit_code: log.exit_code,
    ok: log.ok,
    category: inferCategory(combined),
    primary_message: extractPrimaryMessage(combined),
    file_paths: filePaths,
    package: inferPackage(log, filePaths),
    raw_excerpt: combined.split('\n').slice(0, 80).join('\n'),
    extracted_at: new Date().toISOString(),
  };

  const outputPath = path.join(
    repoRoot,
    '.ai-orchestrator',
    'failures',
    `${failure.execution_id}.json`,
  );
  fs.mkdirSync(path.dirname(outputPath), { recursive: true });
  fs.writeFileSync(outputPath, JSON.stringify(failure, null, 2));

  console.log(
    JSON.stringify(
      {
        ok: true,
        category: failure.category,
        primary_message: failure.primary_message,
        file_paths: failure.file_paths,
        output_path: normalizePath(path.relative(repoRoot, outputPath)),
      },
      null,
      2,
    ),
  );
}

main();

const fs = require('fs');
const path = require('path');

const repoRoot = process.cwd();
const manifestPath = path.resolve(
  process.argv[2] ||
    path.join(repoRoot, '.ai-orchestrator', 'chunks', 'manifest.jsonl'),
);
const errorInput = process.argv[3] || '';
const changedFilesInput = process.argv[4] || '';
const limit = Number(process.argv[5] || 8);

function normalizePath(filePath) {
  return filePath.split(path.sep).join('/');
}

function loadManifest(filePath) {
  const raw = fs.readFileSync(filePath, 'utf8');
  return raw
    .split('\n')
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line) => JSON.parse(line));
}

function parseChangedFiles(input) {
  return input
    .split(',')
    .map((item) => item.trim())
    .filter(Boolean)
    .map(normalizePath);
}

function extractFilePaths(text) {
  const matches = new Set();
  const normalizedText = String(text || '');
  const patterns = [
    /(?:^|[\s("'`])((?:apps|\.github|postman)\/[A-Za-z0-9._/\-]+?\.[A-Za-z0-9]+)(?=$|[\s)"'`:,])/g,
    /(?:^|[\s("'`])((?:README|\.orchestrator)[A-Za-z0-9._/\-]*)(?=$|[\s)"'`:,])/g,
  ];

  for (const pattern of patterns) {
    for (const match of normalizedText.matchAll(pattern)) {
      matches.add(normalizePath(match[1]));
    }
  }

  return [...matches];
}

function inferPackage(text) {
  if (/apps\/web|vite|react|tsx?|frontend/i.test(text)) {
    return 'apps/web';
  }

  if (/apps\/api|nestjs|node|backend|unit_tests|api_/i.test(text)) {
    return 'apps/api';
  }

  if (/workflow|github actions|orchestrator|\.github|yaml/i.test(text)) {
    return '.github';
  }

  return null;
}

function scoreChunk(chunk, context) {
  let score = 0;
  const haystack = `${chunk.path}\n${chunk.text}\n${chunk.symbol_names.join(' ')}\n${chunk.imports.join(' ')}`.toLowerCase();

  if (context.directPaths.has(chunk.path)) {
    score += 120;
  }

  if (context.changedFiles.has(chunk.path)) {
    score += 90;
  }

  if (context.targetPackage && chunk.package === context.targetPackage) {
    score += 25;
  }

  if (context.directPaths.size > 0) {
    for (const directPath of context.directPaths) {
      if (chunk.path.startsWith(path.posix.dirname(directPath))) {
        score += 12;
      }
    }
  }

  for (const term of context.keyTerms) {
    if (haystack.includes(term)) {
      score += 4;
    }
  }

  if (
    context.errorText &&
    /npm test|unit test|assert|jest|mocha/i.test(context.errorText) &&
    /test|assert|run-tests/.test(chunk.path)
  ) {
    score += 15;
  }

  if (
    context.errorText &&
    /npm run build|tsc|typescript|vite/i.test(context.errorText) &&
    /src\/|tsconfig|vite/.test(chunk.path)
  ) {
    score += 15;
  }

  return score;
}

function buildKeyTerms(text) {
  return [...new Set(
    String(text || '')
      .toLowerCase()
      .split(/[^a-z0-9._/-]+/)
      .map((term) => term.trim())
      .filter((term) => term.length >= 4)
      .slice(0, 40),
  )];
}

function main() {
  if (!fs.existsSync(manifestPath)) {
    throw new Error(
      `Chunk manifest not found at ${normalizePath(path.relative(repoRoot, manifestPath))}`,
    );
  }

  const chunks = loadManifest(manifestPath);
  const changedFiles = new Set(parseChangedFiles(changedFilesInput));
  const directPaths = new Set([
    ...extractFilePaths(errorInput),
    ...changedFiles,
  ]);
  const targetPackage = inferPackage(errorInput);
  const keyTerms = buildKeyTerms(errorInput);

  const scored = chunks
    .map((chunk) => ({
      score: scoreChunk(chunk, {
        changedFiles,
        directPaths,
        targetPackage,
        keyTerms,
        errorText: errorInput,
      }),
      chunk,
    }))
    .filter((entry) => entry.score > 0)
    .sort((left, right) => right.score - left.score)
    .slice(0, limit);

  const result = {
    ok: true,
    manifest: normalizePath(path.relative(repoRoot, manifestPath)),
    target_package: targetPackage,
    direct_paths: [...directPaths],
    changed_files: [...changedFiles],
    selected_chunks: scored.map(({ score, chunk }) => ({
      score,
      chunk_id: chunk.chunk_id,
      path: chunk.path,
      start_line: chunk.start_line,
      end_line: chunk.end_line,
      package: chunk.package,
      symbol_names: chunk.symbol_names,
      token_estimate: chunk.token_estimate,
      text: chunk.text,
    })),
  };

  console.log(JSON.stringify(result, null, 2));
}

main();

const fs = require('fs');
const path = require('path');
const { spawnSync } = require('child_process');

const repoRoot = process.cwd();

function normalizePath(filePath) {
  return filePath.split(path.sep).join('/');
}

function readJson(filePath) {
  return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

function runNodeJson(scriptPath, args) {
  const result = spawnSync(process.execPath, [scriptPath, ...args], {
    cwd: repoRoot,
    encoding: 'utf8',
    env: process.env,
    maxBuffer: 10 * 1024 * 1024,
  });

  if (result.status !== 0) {
    throw new Error(result.stderr || result.stdout || `Failed running ${scriptPath}`);
  }

  return JSON.parse(result.stdout);
}

function main() {
  const benchmarkPath =
    process.argv[2] ||
    path.join(repoRoot, '.ai-orchestrator', 'benchmarks', 'common-build-failures.json');
  const manifestPath =
    process.argv[3] ||
    path.join(repoRoot, '.ai-orchestrator', 'chunks', 'manifest.jsonl');
  const limit = process.argv[4] || '5';

  const benchmarks = readJson(benchmarkPath);
  const retrieveScript = path.join(
    repoRoot,
    '.github',
    'workflows',
    'scripts',
    'retrieve-relevant-chunks.js',
  );

  const results = [];

  for (const scenario of benchmarks) {
    const retrieval = runNodeJson(retrieveScript, [
      manifestPath,
      scenario.error_text,
      (scenario.changed_files || []).join(','),
      limit,
    ]);

    const returnedPaths = retrieval.selected_chunks.map((chunk) => chunk.path);
    const expectedHits = (scenario.expected_paths || []).filter((expectedPath) =>
      returnedPaths.includes(expectedPath),
    );

    results.push({
      id: scenario.id,
      category: scenario.category,
      expected_count: (scenario.expected_paths || []).length,
      hit_count: expectedHits.length,
      passed: expectedHits.length > 0,
      expected_paths: scenario.expected_paths || [],
      returned_paths: returnedPaths,
    });
  }

  const passed = results.filter((result) => result.passed).length;
  const summary = {
    ok: true,
    scenarios: results.length,
    passed,
    failed: results.length - passed,
    pass_rate: Number(((passed / results.length) * 100).toFixed(2)),
    results,
  };

  const outputPath = path.join(
    repoRoot,
    '.ai-orchestrator',
    'benchmarks',
    'benchmark-results.json',
  );
  fs.writeFileSync(outputPath, JSON.stringify(summary, null, 2));

  console.log(
    JSON.stringify(
      {
        ok: true,
        scenarios: summary.scenarios,
        passed: summary.passed,
        failed: summary.failed,
        pass_rate: summary.pass_rate,
        output_path: normalizePath(path.relative(repoRoot, outputPath)),
      },
      null,
      2,
    ),
  );
}

main();

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const BASELINE_CHECKS = [
  'api_build_validation',
  'api_unit_tests',
  'web_build_validation',
];

const CHECK_ALIASES = {
  integration_tests: 'api_unit_tests',
};

function parseScalar(value) {
  const trimmed = String(value || '').trim();

  if (
    (trimmed.startsWith('"') && trimmed.endsWith('"')) ||
    (trimmed.startsWith("'") && trimmed.endsWith("'"))
  ) {
    return trimmed.slice(1, -1);
  }

  return trimmed;
}

function parseOrchestratorConfig(source) {
  const config = {
    project: {},
    checks: {},
  };

  const lines = String(source)
    .replace(/\r/g, '')
    .split('\n');

  let section = null;
  let currentCheck = null;
  let collectingCommands = false;

  for (const rawLine of lines) {
    const indent = rawLine.match(/^ */)?.[0]?.length || 0;
    const trimmed = rawLine.trim();

    if (!trimmed || trimmed.startsWith('#')) {
      continue;
    }

    if (indent === 0 && trimmed.endsWith(':')) {
      section = trimmed.slice(0, -1);
      currentCheck = null;
      collectingCommands = false;
      continue;
    }

    if (section === 'project' && indent === 2) {
      const separatorIndex = trimmed.indexOf(':');
      if (separatorIndex === -1) {
        continue;
      }

      const key = trimmed.slice(0, separatorIndex).trim();
      const value = trimmed.slice(separatorIndex + 1).trim();
      config.project[key] = parseScalar(value);
      continue;
    }

    if (section === 'checks' && indent === 2 && trimmed.endsWith(':')) {
      currentCheck = trimmed.slice(0, -1);
      collectingCommands = false;
      config.checks[currentCheck] = {
        commands: [],
      };
      continue;
    }

    if (!currentCheck) {
      continue;
    }

    if (indent === 4 && trimmed === 'commands:') {
      collectingCommands = true;
      continue;
    }

    if (indent === 4) {
      const separatorIndex = trimmed.indexOf(':');
      if (separatorIndex === -1) {
        continue;
      }

      const key = trimmed.slice(0, separatorIndex).trim();
      const value = trimmed.slice(separatorIndex + 1).trim();
      config.checks[currentCheck][key] = parseScalar(value);
      collectingCommands = false;
      continue;
    }

    if (collectingCommands && indent >= 6 && trimmed.startsWith('- ')) {
      config.checks[currentCheck].commands.push(
        parseScalar(trimmed.slice(2)),
      );
    }
  }

  return config;
}

const recommendedChecks = (process.argv[2] || '')
  .split(',')
  .map((c) => c.trim())
  .filter(Boolean);
const configPath = process.argv[3] || '.orchestrator.yml';
const resolvedConfigPath = path.resolve(configPath);
const configDirectory = path.dirname(resolvedConfigPath);

const config = parseOrchestratorConfig(
  fs.readFileSync(resolvedConfigPath, 'utf8'),
);

const checksToRun = [...new Set([...BASELINE_CHECKS, ...recommendedChecks])];

console.log('Baseline checks:', BASELINE_CHECKS);
console.log('Recommended checks:', recommendedChecks);
console.log('Final checks to run:', checksToRun);

for (const check of checksToRun) {
  const resolvedCheck = config.checks?.[check]
    ? check
    : CHECK_ALIASES[check];
  const definition = config.checks?.[resolvedCheck];

  if (!definition) {
    throw new Error(`Unknown check in execution set: ${check}`);
  }

  if (resolvedCheck !== check) {
    console.log(`Resolved check alias: ${check} -> ${resolvedCheck}`);
  }

  const workingDirectory = path.resolve(
    configDirectory,
    definition.workingDirectory ||
      config.project?.defaultWorkingDirectory ||
      '.',
  );

  console.log(`Running check: ${check}`);
  console.log(`Working directory: ${workingDirectory}`);

  for (const command of definition.commands || []) {
    console.log(`Executing: ${command}`);

    execSync(command, {
      cwd: workingDirectory,
      stdio: 'inherit',
    });
  }
}

console.log('All orchestrator checks completed.');

