const assert = require('node:assert/strict');

async function main() {
  const { AppService } = require('../dist/app.service.js');
  const service = new AppService();

  const health = service.getHealth();
  assert.equal(health.ok, true);
  assert.equal(health.service, 'demo-api');
  assert.ok(health.timestamp);

  const overview = service.getOverview();
  assert.equal(overview.product, 'AI Orchestrator Demo');
  assert.equal(Array.isArray(overview.tasks), true);
  assert.equal(overview.metrics.totalTasks, 3);

  console.log('API demo tests passed');
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});

import { Controller, Get } from '@nestjs/common';
import { AppService } from './app.service';

@Controller()
export class AppController {
  constructor(private readonly appService: AppService) {}

  @Get('health')
  getHealth() {
    return this.appService.getHealth();
  }

  @Get('api/overview')
  getOverview() {
    return this.appService.getOverview();
  }
}

import { Module } from '@nestjs/common';
import { AppController } from './app.controller';
import { AppService } from './app.service';

@Module({

  controllers: [AppController],
  providers: [AppService],
})
export class AppModule {}

import { Injectable } from '@nestjs/common';

export type DemoTask = {
  id: number;
  title: string;
  status: 'planned' | 'in-progress' | 'done';
  owner: string;
};

@Injectable()
export class AppService {
  private readonly tasks: DemoTask[] = [
    { id: 1, title: 'Design landing screen', status: 'done', owner: 'Ava' },
    { id: 2, title: 'Build API endpoints', status: 'in-progress', owner: 'Kai' },
    { id: 3, title: 'Wire React dashboard', status: 'planned', owner: 'Mira' },
  ];

  getHealth() {
    return {
      ok: true,
      service: 'demo-api',
      timestamp: new Date().toISOString(),
    };
  }

  getOverview() {
    const doneCount = this.tasks.filter((task) => task.status === 'done').length;

    return {
      product: 'AI Orchestrator Demo',
      summary: 'A small full-stack workspace with a React frontend and NestJS API.',
      metrics: {
        totalTasks: this.tasks.length,
        completedTasks: doneCount,
        activeTasks: this.tasks.filter((task) => task.status === 'in-progress').length,
      },
      tasks: this.tasks,
    };
  }
}

import 'reflect-metadata';
import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';

async function bootstrap() {
  const app = await NestFactory.create(AppModule, { cors: true });
  const port = Number(process.env.PORT ?? 3001);

  await app.listen(port);
  console.log(`Demo API listening on http://localhost:${port}`);
}

void bootstrap();

